mapper.select:
SELECT *,
       CASE
           WHEN title LIKE CONCAT('%', #{q}, '%') THEN 3
           WHEN JSON_CONTAINS(tags, CONCAT('"', #{q}, '"')) THEN 2
           WHEN description LIKE CONCAT('%', #{q}, '%') THEN 1
           ELSE 0
       END AS relevance_score
FROM activities
WHERE status = 'published'
  AND (title LIKE CONCAT('%', #{q}, '%')
       OR JSON_CONTAINS(tags, CONCAT('"', #{q}, '"'))
       OR description LIKE CONCAT('%', #{q}, '%'))

  AND city = #{city}


  AND fee_type = #{feeType}


  AND start_time >= #{startAfter}


  AND start_time <= #{startBefore}


  AND activity_type IN

      #{type}


ORDER BY relevance_score DESC, created_at DESC, id DESC
LIMIT #{limit}

SELECT id, title, location_name, location_lat, location_lng, start_time, current_participants, max_participants, activity_type, city
, (6371000 * 2 * ASIN(SQRT( POWER(SIN(RADIANS(location_lat - #{lat}) / 2), 2) + COS(RADIANS(#{lat})) * COS(RADIANS(location_lat)) * POWER(SIN(RADIANS(location_lng - #{lng}) / 2), 2) ))) AS distance_meters
FROM activities WHERE status = 'published' AND location_lat IS NOT NULL AND location_lng IS NOT NULL AND location_lat BETWEEN #{swLat} AND #{neLat} AND location_lng BETWEEN #{swLng} AND #{neLng} ORDER BY start_time ASC LIMIT #{limit}
